const cert = $('Buscar Certificado por QR (Postgres)').item.json;

// cert.fecha es DATE puro (sin hora/zona) — mismo criterio que en
// generar-certificado: se lee el string YYYY-MM-DD directo, sin Date/Intl.
const MESES = ['enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio', 'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre'];
const fechaStr = typeof cert.fecha === 'string' ? cert.fecha : cert.fecha.toISOString();
const [anio, mes, dia] = fechaStr.slice(0, 10).split('-').map(Number);
const fechaEmision = `${String(dia).padStart(2, '0')} de ${MESES[mes - 1]} de ${anio}`;

return [{
  json: {
    autentico: true,
    codigoUnico: cert.codigoUnico,
    nombreCompleto: cert.nombreCompleto,
    cedula: cert.cedula,
    carrera: cert.carrera,
    nivel: cert.nivel,
    periodoActual: cert.periodoActual,
    modalidad: cert.modalidad,
    fechaEmision,
    firmanteNombre: cert.firmanteNombre,
    firmanteCargo: cert.firmanteCargo
  }
}];
